DROP TABLE IF EXISTS [ec_pages];
CREATE TABLE "ec_pages" ("id" text primary key, "slug" text, "status" text default 'draft', "author_id" text, "primary_byline_id" text, "created_at" text default (datetime('now')), "updated_at" text default (datetime('now')), "published_at" text, "scheduled_at" text, "deleted_at" text, "version" integer default 1, "live_revision_id" text references "revisions" ("id"), "draft_revision_id" text references "revisions" ("id"), "locale" text default 'en' not null, "translation_group" text, "title" TEXT NOT NULL DEFAULT '', "content" JSON, constraint "ec_pages_slug_locale_unique" unique ("slug", "locale"));

INSERT OR IGNORE INTO [ec_pages] ([id],[slug],[status],[author_id],[primary_byline_id],[created_at],[updated_at],[published_at],[scheduled_at],[deleted_at],[version],[live_revision_id],[draft_revision_id],[locale],[translation_group],[title],[content]) VALUES ('01KP1Y1X17N72PD53X78WWT5MA','about','published',NULL,NULL,'2026-04-12T22:47:31.111Z','2026-04-12T22:47:31.111Z','2026-04-12T22:47:31.111Z',NULL,NULL,1,NULL,NULL,'en','01KP1Y1X17N72PD53X78WWT5MA','About','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"A place for writing about software, design, and the occasional stray thought. No posting schedule, no newsletter funnel. Just things I wanted to write down."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Built with Astro and EmDash. The source is open if you want to see how it works."}]}]');

DROP TABLE IF EXISTS [ec_posts];
CREATE TABLE "ec_posts" ("id" text primary key, "slug" text, "status" text default 'draft', "author_id" text, "primary_byline_id" text, "created_at" text default (datetime('now')), "updated_at" text default (datetime('now')), "published_at" text, "scheduled_at" text, "deleted_at" text, "version" integer default 1, "live_revision_id" text references "revisions" ("id"), "draft_revision_id" text references "revisions" ("id"), "locale" text default 'en' not null, "translation_group" text, "title" TEXT NOT NULL DEFAULT '', "featured_image" TEXT, "content" JSON, "excerpt" TEXT, constraint "ec_posts_slug_locale_unique" unique ("slug", "locale"));

INSERT OR IGNORE INTO [ec_posts] ([id],[slug],[status],[author_id],[primary_byline_id],[created_at],[updated_at],[published_at],[scheduled_at],[deleted_at],[version],[live_revision_id],[draft_revision_id],[locale],[translation_group],[title],[featured_image],[content],[excerpt]) VALUES ('01KP1Y1X60T1NCJQZJY9J42MHQ','building-for-the-long-term','published',NULL,'01KP1Y1X15H4D3WWSM22CGQKRM','2026-04-12T22:47:31.264Z','2026-04-12T22:47:31.264Z','2026-04-12T22:47:31.264Z',NULL,NULL,1,NULL,NULL,'en','01KP1Y1X60T1NCJQZJY9J42MHQ','Building for the Long Term','{"provider":"local","id":"01KP1Y1X59P7P43WY1GEP2TD6F","alt":"Code on a monitor in a dark room","width":1200,"height":800,"mimeType":"image/jpeg","filename":"building-long-term.jpg","meta":{"storageKey":"01KP1Y1X59P7P43WY1GEP2TD6F.jpg"}}','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Every few years the industry collectively decides that everything we''ve been doing is wrong and there''s a better way. New frameworks, new paradigms, new build tools. The churn is relentless, and if you''re not careful, you spend more time migrating than building."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"I''ve been writing software long enough to have seen several of these cycles. jQuery to Backbone to Angular to React to whatever comes next. Each transition felt urgent at the time. Looking back, the things that actually mattered were rarely about the framework."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"What survives"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Clean data models survive. Clear boundaries between systems survive. Good naming survives. The decision to keep things simple when you could have made them clever - that definitely survives."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"What doesn''t survive is code that was written to impress, abstractions built for problems that never materialized, and architectures designed around a framework''s opinions rather than the domain''s reality."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The best code I''ve written is boring. It reads like prose, does one thing well, and doesn''t require a PhD in category theory to understand. The worst code I''ve written was technically impressive at the time."}]}]','The frameworks will change. The databases will change. What survives is the clarity of your thinking.');
INSERT OR IGNORE INTO [ec_posts] ([id],[slug],[status],[author_id],[primary_byline_id],[created_at],[updated_at],[published_at],[scheduled_at],[deleted_at],[version],[live_revision_id],[draft_revision_id],[locale],[translation_group],[title],[featured_image],[content],[excerpt]) VALUES ('01KP1Y1X6SQ7K0QBHN0CEGXN01','the-case-for-static','published',NULL,'01KP1Y1X15H4D3WWSM22CGQKRM','2026-04-12T22:47:31.289Z','2026-04-12T22:47:31.289Z','2026-04-12T22:47:31.289Z',NULL,NULL,1,NULL,NULL,'en','01KP1Y1X6SQ7K0QBHN0CEGXN01','The Case for Static','{"provider":"local","id":"01KP1Y1X6GT4CWX1KP5860GH89","alt":"Laptop and coffee on a wooden table","width":1200,"height":800,"mimeType":"image/jpeg","filename":"case-for-static.jpg","meta":{"storageKey":"01KP1Y1X6GT4CWX1KP5860GH89.jpg"}}','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"There''s a certain irony in the fact that the web started static, went dynamic, and is now swinging back toward static again. But the static sites of today aren''t the hand-coded HTML pages of 1998. They''re generated, optimized, and deployed to edge networks that serve them in milliseconds."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The pitch for server-rendered everything was compelling: dynamic content, personalization, real-time data. But most sites don''t need most of that most of the time. A blog post doesn''t need to be rendered on every request. A product page doesn''t change every second."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"The performance argument"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"A static file served from a CDN is as fast as the web gets. No cold starts, no database queries, no server-side rendering overhead. The Time to First Byte is essentially the network latency to your nearest edge node. You can''t beat physics."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"And when you do need dynamic behavior, you can add it surgically. An island of interactivity in a sea of static HTML. The best of both worlds, without paying the cost of either at all times."}]}]','Static sites aren''t a step backwards. They''re what you get when you take performance and simplicity seriously.');
INSERT OR IGNORE INTO [ec_posts] ([id],[slug],[status],[author_id],[primary_byline_id],[created_at],[updated_at],[published_at],[scheduled_at],[deleted_at],[version],[live_revision_id],[draft_revision_id],[locale],[translation_group],[title],[featured_image],[content],[excerpt]) VALUES ('01KP1Y1X7F9Q5RMR71MA5QJQA1','learning-in-public','published',NULL,NULL,'2026-04-12T22:47:31.312Z','2026-04-12T22:47:31.312Z','2026-04-12T22:47:31.311Z',NULL,NULL,1,NULL,NULL,'en','01KP1Y1X7F9Q5RMR71MA5QJQA1','Learning in Public','{"provider":"local","id":"01KP1Y1X7490BAMMG1X95JSPQJ","alt":"Notebook and pen on a desk","width":1200,"height":800,"mimeType":"image/jpeg","filename":"learning-in-public.jpg","meta":{"storageKey":"01KP1Y1X7490BAMMG1X95JSPQJ.jpg"}}','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"I started writing about things I was learning not because I had anything original to say, but because I kept forgetting what I''d figured out. The blog posts were notes to my future self, published publicly more out of laziness than courage."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"What I didn''t expect was how much the writing itself would accelerate the learning. There''s a particular kind of clarity that comes from trying to explain something to someone else. The gaps in your understanding, which you can happily ignore when the knowledge lives only in your head, become painfully obvious when you try to put it into sentences."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"The fear of being wrong"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The biggest barrier isn''t time or writing skill. It''s the fear of publishing something that turns out to be wrong. But here''s the thing: being wrong publicly is one of the most efficient ways to learn. Someone will correct you, often kindly, and you''ll remember that correction forever."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The posts that helped me most weren''t written by experts. They were written by people one step ahead of me on the same path, in language that hadn''t yet been polished into abstraction. There''s a place for that kind of writing, and it''s more valuable than most people realize."}]}]','Writing about what you''re learning is the fastest way to find out what you don''t actually understand.');
INSERT OR IGNORE INTO [ec_posts] ([id],[slug],[status],[author_id],[primary_byline_id],[created_at],[updated_at],[published_at],[scheduled_at],[deleted_at],[version],[live_revision_id],[draft_revision_id],[locale],[translation_group],[title],[featured_image],[content],[excerpt]) VALUES ('01KP1Y1XCC2AXYZEYATNWKJ8YN','small-tools-big-impact','published',NULL,NULL,'2026-04-12T22:47:31.468Z','2026-04-12T22:47:31.468Z','2026-04-12T22:47:31.468Z',NULL,NULL,1,NULL,NULL,'en','01KP1Y1XCC2AXYZEYATNWKJ8YN','Small Tools, Big Impact','{"provider":"local","id":"01KP1Y1XC2VCY0V63PNXD4WKP7","alt":"Wrenches and hand tools hanging on a workshop wall","width":1200,"height":800,"mimeType":"image/jpeg","filename":"small-tools.jpg","meta":{"storageKey":"01KP1Y1XC2VCY0V63PNXD4WKP7.jpg"}}','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"There''s a class of software that doesn''t get enough appreciation. Not the frameworks or the platforms or the IDEs, but the small, sharp tools that solve one problem so well you stop thinking about them. They become invisible, which is the highest compliment you can pay a tool."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"I''m talking about things like ripgrep, which searches code so fast it changed how I think about searching. Or jq, which makes JSON feel like a first-class data format in the terminal. Or curl, which has been quietly powering the internet''s plumbing for decades."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"The Unix philosophy, revisited"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Do one thing well. The advice is old enough to be a cliche, but the best modern tools still follow it. They don''t try to be platforms. They don''t have plugin ecosystems or configuration languages or startup wizards. They do their job and they compose with other tools that do theirs."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The temptation is always to add more. One more feature, one more option, one more integration. But every addition is a decision someone has to make, a path through the code that has to be maintained, a thing that can break. The best tools resist this. They stay small, and in staying small, they stay reliable."}]}]','The best developer tools do one thing well and get out of your way. A love letter to focused software.');
INSERT OR IGNORE INTO [ec_posts] ([id],[slug],[status],[author_id],[primary_byline_id],[created_at],[updated_at],[published_at],[scheduled_at],[deleted_at],[version],[live_revision_id],[draft_revision_id],[locale],[translation_group],[title],[featured_image],[content],[excerpt]) VALUES ('01KP1Y1XH3ZTHP60DBGDDW9S2J','designing-with-constraints','published',NULL,NULL,'2026-04-12T22:47:31.619Z','2026-04-12T22:47:31.619Z','2026-04-12T22:47:31.619Z',NULL,NULL,1,NULL,NULL,'en','01KP1Y1XH3ZTHP60DBGDDW9S2J','Designing with Constraints','{"provider":"local","id":"01KP1Y1XGWPK87CEZQ039M7KX4","alt":"Pencils and design tools on a desk","width":1200,"height":800,"mimeType":"image/jpeg","filename":"designing-with-constraints.jpg","meta":{"storageKey":"01KP1Y1XGWPK87CEZQ039M7KX4.jpg"}}','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Give a designer a blank canvas and unlimited time, and they''ll often produce something mediocre. Give them a tight brief, a small screen, and a deadline, and they''ll surprise you. This isn''t a paradox - it''s how creativity actually works."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Constraints force decisions. When you can''t use more than two typefaces, you have to choose carefully. When the page has to load in under a second, every element earns its place. When the interface has to work on a 320px screen, you discover what''s truly essential."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Embracing the box"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The web itself is a constraint. HTML flows in one direction. CSS has a box model. Browsers have viewport sizes and font rendering quirks. You can fight these constraints or you can work with them, and the results are dramatically different."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The designs I admire most don''t look like they were forced through a framework. They look like they grew naturally from the medium, respecting its grain rather than working against it. That only happens when you treat constraints as creative partners rather than enemies."}]}]','Limitations aren''t obstacles to creativity. They''re the structure that makes creativity possible.');
INSERT OR IGNORE INTO [ec_posts] ([id],[slug],[status],[author_id],[primary_byline_id],[created_at],[updated_at],[published_at],[scheduled_at],[deleted_at],[version],[live_revision_id],[draft_revision_id],[locale],[translation_group],[title],[featured_image],[content],[excerpt]) VALUES ('01KP1Y1XNVMT5VP3N3TH6H1R1R','a-weekend-with-a-side-project','published',NULL,NULL,'2026-04-12T22:47:31.771Z','2026-04-12T22:47:31.771Z','2026-04-12T22:47:31.771Z',NULL,NULL,1,NULL,NULL,'en','01KP1Y1XNVMT5VP3N3TH6H1R1R','A Weekend with a Side Project','{"provider":"local","id":"01KP1Y1XNKX3FSW7MVMRK795Z4","alt":"Code on a screen with a dark theme","width":1200,"height":800,"mimeType":"image/jpeg","filename":"weekend-side-project.jpg","meta":{"storageKey":"01KP1Y1XNKX3FSW7MVMRK795Z4.jpg"}}','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Saturday morning. Coffee''s made, the house is quiet, and I''ve got an idea that''s been nagging at me all week. Not a good idea, necessarily - just a persistent one. A small tool that does a thing I keep doing manually. How hard could it be?"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"This is the best kind of programming. No requirements document, no sprint planning, no pull request reviews. Just a text editor and a problem. The freedom to make terrible architectural decisions, rewrite everything twice, and follow tangents that turn out to be dead ends."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Why side projects matter"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Side projects are where you learn things your day job would never teach you. Not because the problems are harder, but because you''re free to take risks. Try a language you''ve never used. Build something without a framework. Deploy to a platform you''ve only read about. The stakes are zero, which makes the learning maximum."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"By Sunday evening, the thing sort of works. It''s rough, the error handling is nonexistent, and the README is a single sentence. But it solves the problem I set out to solve, and I learned three things I didn''t know on Friday. Not a bad weekend."}]}]','No stakeholders, no deadlines, no Jira tickets. Just you and a dumb idea that might turn into something.');
INSERT OR IGNORE INTO [ec_posts] ([id],[slug],[status],[author_id],[primary_byline_id],[created_at],[updated_at],[published_at],[scheduled_at],[deleted_at],[version],[live_revision_id],[draft_revision_id],[locale],[translation_group],[title],[featured_image],[content],[excerpt]) VALUES ('01KP1Y1XTK5D3RH212W8NV2YC1','notes-on-simplicity','published',NULL,NULL,'2026-04-12T22:47:31.923Z','2026-04-12T22:47:31.923Z','2026-04-12T22:47:31.923Z',NULL,NULL,1,NULL,NULL,'en','01KP1Y1XTK5D3RH212W8NV2YC1','Notes on Simplicity','{"provider":"local","id":"01KP1Y1XTBHXK8HH5DYZKM6NAX","alt":"Geometric pattern carved into white paper","width":1200,"height":800,"mimeType":"image/jpeg","filename":"notes-on-simplicity.jpg","meta":{"storageKey":"01KP1Y1XTBHXK8HH5DYZKM6NAX.jpg"}}','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"Every piece of software starts simple. A few files, a clear purpose, a small surface area. Then features get added, edge cases get handled, and before long you''re looking at something that requires a diagram to understand. This isn''t inevitable, but it takes discipline to prevent."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The hard part of simplicity isn''t the initial design. It''s the ongoing resistance to complication. Every feature request, every bug fix, every refactor is an opportunity to add complexity. Saying no is the most important design skill, and the least celebrated."}]},{"_type":"block","style":"h2","children":[{"_type":"span","text":"Removing as a feature"}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"The best version of a product often has fewer features than the previous one. Not because features were missing, but because someone had the courage to remove things that weren''t earning their keep. Every feature has a cost - in maintenance, in cognitive load, in the weight of the interface."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Simplicity is a practice, not a destination. You never arrive at simple. You just keep asking: is this necessary? Could this be clearer? Is there a way to solve this problem by removing something instead of adding something? The answer is yes more often than you''d expect."}]}]','Simplicity isn''t the absence of complexity. It''s the result of understanding a problem well enough to solve it cleanly.');
INSERT OR IGNORE INTO [ec_posts] ([id],[slug],[status],[author_id],[primary_byline_id],[created_at],[updated_at],[published_at],[scheduled_at],[deleted_at],[version],[live_revision_id],[draft_revision_id],[locale],[translation_group],[title],[featured_image],[content],[excerpt]) VALUES ('01KP1Y1XTQCRVNBQJM1YK4CX60','work-in-progress','draft',NULL,NULL,'2026-04-12T22:47:31.927Z','2026-04-12T22:47:31.927Z',NULL,NULL,NULL,1,NULL,NULL,'en','01KP1Y1XTQCRVNBQJM1YK4CX60','Work in Progress',NULL,'[{"_type":"block","style":"normal","children":[{"_type":"span","text":"This is a draft post that won''t appear in the public listing."}]}]','This post is still being written.');

